sql:
SELECT COUNT(*) 
FROM exam_conflicts 
WHERE conflict_type = 'time' AND resolved = 0;

SELECT COUNT(*) AS total_conflicts_resolved
FROM exam_conflicts
WHERE resolved = 1;

SELECT COUNT(DISTINCT ec.exam_id) AS total_exams_with_conflicts
FROM (
  SELECT exam_id1 AS exam_id FROM exam_conflicts
  UNION
  SELECT exam_id2 AS exam_id FROM exam_conflicts
) ec;

SELECT COUNT(*) AS total_unresolved_conflicts
FROM exam_conflicts
WHERE resolved = 0;

